// Получение символа из query параметра
const query = $input.first().json.query || {};
const symbol = (query.symbol || 'ETHUSDT').toUpperCase();

return [{ json: { symbol } }];

const items = $input.all();
const symbol = items[0].json.symbol;

// Парсинг свечей
function parseCandles(data) {
  return data.map(c => ({
    open: parseFloat(c[1]),
    high: parseFloat(c[2]),
    low: parseFloat(c[3]),
    close: parseFloat(c[4]),
    volume: parseFloat(c[5])
  }));
}

// Анализ свечей
function analyze(candles, tf) {
  if (!candles || candles.length < 20) return { direction: 'NEUTRAL', score: 0 };

  const c = candles[candles.length - 1];
  const prev = candles[candles.length - 2];

  let bull = 0, bear = 0;

  // Объём
  const avgVol = candles.slice(-20).reduce((s, x) => s + x.volume, 0) / 20;
  if (c.volume > avgVol * 1.5) {
    c.close > c.open ? bull += 2 : bear += 2;
  }

  // Тело свечи
  const body = Math.abs(c.close - c.open);
  const range = c.high - c.low;
  if (range > 0 && body / range > 0.7) {
    c.close > c.open ? (bull += 3, bull += ' Marubozu') : (bear += 3, bear += ' Marubozu');
  }

  // Тени
  const lower = Math.min(c.open, c.close) - c.low;
  const upper = c.high - Math.max(c.open, c.close);
  if (lower > body * 2) bull += 2;
  if (upper > body * 2) bear += 2;

  // RSI
  let gains = [], losses = [];
  for (let i = Math.max(1, candles.length - 14); i < candles.length; i++) {
    const diff = candles[i].close - candles[i-1].close;
    diff > 0 ? gains.push(diff) : losses.push(-diff);
  }
  const avgG = gains.length ? gains.reduce((a,b)=>a+b,0)/14 : 0;
  const avgL = losses.length ? losses.reduce((a,b)=>a+b,0)/14 : 0;
  const rsi = 100 - (100 / (1 + avgG/(avgL||1)));
  if (rsi < 30) bull += 2;
  else if (rsi > 70) bear += 2;

  // EMA
  const ema9 = candles.slice(-9).reduce((s, x) => s + x.close, 0) / 9;
  const ema21 = candles.slice(-21).reduce((s, x) => s + x.close, 0) / 21;
  if (ema9 > ema21) bull += 2;
  else bear += 2;

  const total = bull + bear;
  let dir = 'NEUTRAL';
  if (bull > bear * 1.3 && total > 4) dir = 'LONG';
  else if (bear > bull * 1.3 && total > 4) dir = 'SHORT';

  return { direction: dir, score: Math.max(bull, bear), rsi: Math.round(rsi) };
}

// Анализ стакана
function analyzeOB(ob) {
  if (!ob || !ob.bids || !ob.asks) return { direction: 'NEUTRAL', score: 0 };

  const bid1 = parseFloat(ob.bids[0][1]);
  const ask1 = parseFloat(ob.asks[0][1]);
  const dom = (bid1 - ask1) / (bid1 + ask1);

  let score = 0;
  if (dom > 0.3) score = 3;
  else if (dom > 0.1) score = 1;
  else if (dom < -0.3) score = -3;
  else if (dom < -0.1) score = -1;

  const dir = score > 0 ? 'LONG' : score < 0 ? 'SHORT' : 'NEUTRAL';

  return { direction: dir, score: Math.abs(score), spread: ((parseFloat(ob.asks[0][0]) - parseFloat(ob.bids[0][0])) / ((parseFloat(ob.asks[0][0]) + parseFloat(ob.bids[0][0])) / 2) * 100).toFixed(4) };
}

// Найти данные
let candles1m = [], candles5m = [], candles1h = [], ob = {};

for (const item of items) {
  if (item.json[0] && item.json[0][1]) candles1m = parseCandles(item.json);
  else if (item.json[0] && item.json[0][4] && !item.json.spread) candles5m = parseCandles(item.json);
  else if (item.json[0] && item.json[0][4] && candles5m.length === 0) candles5m = parseCandles(item.json);
  else if (item.json.bids) ob = item.json;
}

// Повторный запрос если не получены
if (candles1m.length === 0) {
  const resp1m = await $http.request({ method: 'GET', url: `https://api.binance.com/api/v3/klines?symbol=${symbol}&interval=1m&limit=100` });
  candles1m = parseCandles(resp1m.json);
}

const a1m = analyze(candles1m, '1m');
const a5m = analyze(candles5m, '5m');
const a1h = analyze(candles1h, '1h');
const aob = analyzeOB(ob);

// Итог
const dirs = [a1m.direction, a5m.direction, a1h.direction, aob.direction];
const longs = dirs.filter(d => d === 'LONG').length;
const shorts = dirs.filter(d => d === 'SHORT').length;

let finalDir = 'WAIT';
let conf = 0;

if (longs >= 2) { finalDir = 'LONG'; conf = Math.min(0.85, 0.5 + longs * 0.12); }
else if (shorts >= 2) { finalDir = 'SHORT'; conf = Math.min(0.85, 0.5 + shorts * 0.12); }

return [{ json: {
  symbol,
  analysis: { '1m': a1m, '5m': a5m, '1h': a1h, orderbook: aob },
  final: { direction: finalDir, confidence: Math.round(conf * 100) / 100 },
  timestamp: new Date().toISOString()
} }];
